    const playerStatDefs = [
      ["goals", "Goals"],
      ["assists", "Assists"],
      ["productivity", "Productivity"],
      ["rating", "Rating"],
      ["cards", "Cards"],
      ["man-of-the-match", "MoM"]
    ];
    const clubStatDefs = [
      ["goals", "Goals"],
      ["attendance", "Attendance"],
      ["injuries", "Injuries"],
      ["possession", "Possession"],
      ["cards", "Cards"]
    ];
    const playerColLabels = {
      goals: "Goals",
      assists: "Assists",
      productivity: "Pts",
      rating: "Rating",
      cards: "Cards",
      "man-of-the-match": "MoM"
    };
