        const enriched = rows.map((r) => ({ ...r, _sortVals: [0, r.clubName, ...r.vals] }));
        enriched.sort((a, b) => (parseFloat(b._sortVals[2]) || 0) - (parseFloat(a._sortVals[2]) || 0));
        enriched.forEach((r, i) => {
          r._rank = i + 1;
          r._sortVals[0] = i + 1;
        });
